// frontend/src/components/Dashboard/Dashboard.js
import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Grid,
  Paper,
  Typography,
  Button,
  AppBar,
  Toolbar,
  IconButton,
  Menu,
  MenuItem,
  Avatar,
  Divider,
  Alert,
  CircularProgress,
  Card,
  CardContent,
  Chip,
  useTheme,
  useMediaQuery
} from '@mui/material';
import {
  AccountCircle,
  Logout,
  Refresh,
  TrendingUp,
  TrendingDown,
  AccountBalanceWallet,
  ShowChart,
  History,
  Sync,
  Visibility,
  VisibilityOff,
  AdminPanelSettings
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import authService from '../../services/authService';
import { useAuth } from '../../contexts/AuthContext';
import dashboardService from '../../services/dashboardService';
import logger from '../../utils/logger';
import StatsCards from './StatsCards';
import PNLCard from './PNLCard';
import TradesTable from './TradesTable';
import AccountBalance from './AccountBalance';
import OpenPositions from './OpenPositions';
import Profile from './Profile';
import DateFilter from './DateFilter';

const Dashboard = () => {
  const navigate = useNavigate();
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const { user, logout } = useAuth(); // Modificado: user agora vem do AuthContext

  // const [user, setUser] = useState(null); // Removido: user agora vem do AuthContext
  const [anchorEl, setAnchorEl] = useState(null);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [error, setError] = useState('');
  const [showProfile, setShowProfile] = useState(false);
  const [autoSyncStatus, setAutoSyncStatus] = useState(false);
  const [autoSyncLoading, setAutoSyncLoading] = useState(false);
  const [hideValues, setHideValues] = useState(false);
  const [dateFilters, setDateFilters] = useState({});
  const [dashboardData, setDashboardData] = useState({
    stats: null,
    openTrades: [],
    closedTrades: [],
    profitData: [],
    balance: null
  });

  useEffect(() => {
    loadDashboardData();
    checkAutoSyncStatus();

    // Timer para atualização automática a cada 30 segundos
    const interval = setInterval(() => {
      loadDashboardData();
      checkAutoSyncStatus();
      // Recarregar histórico de trades também
      loadClosedTrades(dateFilters);
    }, 30000); // 30 segundos

    // Cleanup do timer quando o componente for desmontado
    return () => clearInterval(interval);
  }, []);

  const loadClosedTrades = async (filters = {}) => {
    try {
      const closedTradesResponse = await dashboardService.getClosedTrades(filters);
      if (closedTradesResponse.success) {
        setDashboardData(prev => ({
          ...prev,
          closedTrades: closedTradesResponse.data
        }));
      }
    } catch (error) {
      console.error('Erro ao carregar trades fechados:', error);
      toast.error('Erro ao carregar trades fechados');
    }
  };

  const loadDashboardData = async () => {
    try {
      setLoading(true);
      setError('');

      // Nota: Verificação de sessão removida para evitar logout automático
      // A autenticação é verificada automaticamente pelos interceptadores do axios

      // Carregar dados do dashboard em paralelo
      const [stats, openTrades, closedTrades, profitData, balance] = await Promise.all([
        dashboardService.getUserStats(),
        dashboardService.getOpenTrades(),
        dashboardService.getClosedTrades(dateFilters),
        dashboardService.getProfitCurveData(),
        dashboardService.getAccountBalance()
      ]);

      // Log seguro apenas do status
      logger.secure('Dashboard data loaded successfully');

      setDashboardData({
        stats: stats?.data || stats,
        openTrades: Array.isArray(openTrades?.data) ? openTrades.data : (Array.isArray(openTrades) ? openTrades : []),
        closedTrades: Array.isArray(closedTrades?.data) ? closedTrades.data : (Array.isArray(closedTrades) ? closedTrades : []),
        profitData: Array.isArray(profitData?.data) ? profitData.data : (Array.isArray(profitData) ? profitData : []),
        balance
      });
    } catch (error) {
      console.error('Erro ao carregar dashboard:', error);

      // Verificar se é erro de autenticação
      if (error.message === 'Não autenticado' || error.message === 'Login necessário' || error.status === 401) {
        setError('Sessão expirada. Você será redirecionado para o login.');
        // O interceptador já vai lidar com o redirecionamento
      } else {
        setError('Erro ao carregar dados do dashboard');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadDashboardData();
    setRefreshing(false);
    toast.success('Dados atualizados!');
  };

  const handleSyncTrades = async () => {
    try {
      setRefreshing(true);
      await dashboardService.syncTrades();
      await loadDashboardData();
      toast.success('Trades sincronizados com sucesso!');
    } catch (error) {
      console.error('Erro ao sincronizar trades:', error);
      toast.error('Erro ao sincronizar trades');
    } finally {
      setRefreshing(false);
    }
  };

  const checkAutoSyncStatus = async () => {
    try {
      const response = await dashboardService.getAutoSyncStatus();
      setAutoSyncStatus(response.running || false);
    } catch (error) {
      console.error('Erro ao verificar status da sincronização automática:', error);

      // Verificar se é erro de autenticação
      if (error.message === 'Login necessário' || error.status === 401) {
        // O interceptador já vai lidar com o redirecionamento
        return;
      }
    }
  };

  const handleToggleAutoSync = async () => {
    try {
      setAutoSyncLoading(true);

      if (autoSyncStatus) {
        await dashboardService.stopAutoSync();
        toast.success('Sincronização automática desativada!');
      } else {
        await dashboardService.startAutoSync();
        toast.success('Sincronização automática ativada!');
      }

      await checkAutoSyncStatus();
    } catch (error) {
      console.error('Erro ao alterar sincronização automática:', error);
      toast.error('Erro ao alterar sincronização automática');
    } finally {
      setAutoSyncLoading(false);
    }
  };

  const handleMenuOpen = (event) => {
    setAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setAnchorEl(null);
  };

  const handleLogout = async () => {
    try {
      setAnchorEl(null);
      await logout();
      // O logout vai redirecionar automaticamente
    } catch (error) {
      console.error('Erro no logout:', error);
    }
  };

  const handleGoToAdmin = () => {
    console.log('Navegando para admin dashboard...');
    console.log('User:', user);
    console.log('User email:', user?.email);
    navigate('/admin');
  };

  const handleToggleValues = () => {
    setHideValues(!hideValues);
  };

  const handleDateFilterChange = async (filters) => {
    setDateFilters(filters);
    await loadClosedTrades(filters);
  };

  // Recarregar trades fechados quando os filtros mudarem
  useEffect(() => {
    if (Object.keys(dateFilters).length > 0) {
      loadClosedTrades(dateFilters);
    }
  }, [dateFilters]);

  // Removido o loading que causava o desaparecimento da tela inteira
  // O dashboard agora permanece visível durante as atualizações

  return (
    <Box sx={{ flexGrow: 1, minHeight: '100vh', bgcolor: 'background.default' }}>
      {/* Seção fixa no topo - AppBar + Cards de Estatísticas */}
      <Box
        sx={{
          position: 'sticky',
          top: 0,
          zIndex: 1100,
          backgroundColor: 'background.default'
        }}
      >
        {/* AppBar */}
        <AppBar position="static" elevation={0} sx={{ bgcolor: 'background.paper', borderBottom: 1, borderColor: 'divider' }}>
          <Toolbar>
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, flexGrow: 1 }}>
              <Typography
                variant="h6"
                component="div"
                sx={{
                  fontWeight: 'bold',
                  color: 'primary.main'
                }}
              >
                Nautilus Automação
              </Typography>

              {/* Campo do Nome do Usuário REMOVIDO */}

              {/* Indicador sutil de loading inicial */}
              {loading && (
                <CircularProgress
                  size={20}
                  thickness={4}
                  sx={{
                    color: 'primary.main',
                    opacity: 0.7
                  }}
                />
              )}
            </Box>

            {/* Mensagem de Boas-vindas centralizada */}
            <Box sx={{ 
              position: 'absolute', 
              left: '50%', 
              transform: 'translateX(-50%)',
              display: 'flex',
              alignItems: 'center',
              gap: 1,
              zIndex: 1
            }}>
              {(() => {
                // Removido logs sensíveis por segurança

                if (user && user.full_name && user.full_name.trim()) {
                  return (
                    <Typography 
                      variant="h6" 
                      sx={{ 
                        color: 'text.primary',
                        fontWeight: 'medium',
                        whiteSpace: 'nowrap'
                      }}
                    >
                      Bem-vindo, {user.full_name.trim()}!
                    </Typography>
                  );
                } else if (user && user.email) {
                  return (
                    <Typography 
                      variant="h6" 
                      sx={{ 
                        color: 'text.primary',
                        fontWeight: 'medium',
                        whiteSpace: 'nowrap'
                      }}
                    >
                      Bem-vindo, {user.email.split('@')[0]}!
                    </Typography>
                  );
                } else if (user) {
                  return (
                    <Typography 
                      variant="h6" 
                      sx={{ 
                        color: 'text.primary',
                        fontWeight: 'medium',
                        whiteSpace: 'nowrap'
                      }}
                    >
                      Bem-vindo, Usuário!
                    </Typography>
                  );
                } else {
                  return (
                    <Typography 
                      variant="h6" 
                      sx={{ 
                        color: 'text.secondary',
                        fontWeight: 'medium',
                        whiteSpace: 'nowrap'
                      }}
                    >
                      Carregando...
                    </Typography>
                  );
                }
              })()} 
            </Box>

            {/* Botões de ação */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mr: 2 }}>
              {/* Botão Admin - apenas para usuários administradores */}
              {user?.email === 'willian@lexxusadm.com.br' && (
                <Button
                  startIcon={<AdminPanelSettings />}
                  onClick={handleGoToAdmin}
                  size="small"
                  variant="contained"
                  color="secondary"
                  sx={{ 
                    display: { xs: 'none', md: 'flex' },
                    background: 'linear-gradient(45deg, #ff6b35 30%, #f7931e 90%)',
                    fontWeight: 'bold',
                    '&:hover': {
                      background: 'linear-gradient(45deg, #e55a2b 30%, #e8841a 90%)',
                      transform: 'scale(1.02)'
                    }
                  }}
                >
                  Admin
                </Button>
              )}

              <Button
                startIcon={<Sync />}
                onClick={handleToggleAutoSync}
                disabled={autoSyncLoading}
                size="small"
                variant={autoSyncStatus ? "contained" : "outlined"}
                color={autoSyncStatus ? "success" : "primary"}
                sx={{ display: { xs: 'none', md: 'flex' } }}
              >
                {autoSyncStatus ? 'Auto-Sync ON' : 'Auto-Sync OFF'}
              </Button>

              <Button
                startIcon={<Sync />}
                onClick={handleSyncTrades}
                disabled={refreshing}
                size="small"
                variant="outlined"
                sx={{ display: { xs: 'none', sm: 'flex' } }}
              >
                Sincronizar
              </Button>

              <IconButton
                onClick={() => setHideValues(!hideValues)}
                color="default"
                title={hideValues ? "Mostrar valores" : "Ocultar valores"}
                sx={{
                  color: hideValues ? 'white' : 'inherit',
                  backgroundColor: hideValues ? 'primary.main' : 'transparent',
                  '&:hover': {
                    backgroundColor: hideValues ? 'primary.dark' : 'action.hover'
                  }
                }}
              >
                {hideValues ? <VisibilityOff /> : <Visibility />}
              </IconButton>

              <IconButton
                onClick={handleRefresh}
                disabled={refreshing}
                color="primary"
              >
                <Refresh />
              </IconButton>
            </Box>

            {/* Menu do usuário */}
            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
              {!isMobile && user && user.full_name && user.full_name.trim() && (
                <Typography variant="body2" color="text.primary">
                  Olá, {user.full_name.trim().split(' ')[0]}
                </Typography>
              )}
              <IconButton
                size="large"
                onClick={handleMenuOpen}
                color="inherit"
              >
                <Avatar sx={{ width: 32, height: 32, bgcolor: 'primary.main' }}>
                  {user?.full_name?.trim()?.charAt(0) || <AccountCircle />}
                </Avatar>
              </IconButton>
            </Box>

            <Menu
              anchorEl={anchorEl}
              open={Boolean(anchorEl)}
              onClose={handleMenuClose}
              transformOrigin={{ horizontal: 'right', vertical: 'top' }}
              anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
            >
              <MenuItem disabled>
                <Typography variant="body2" color="text.secondary">
                  {user?.email}
                </Typography>
              </MenuItem>
              <Divider />
              {/* Opção Admin no menu - apenas para administradores */}
              {user?.email === 'willian@lexxusadm.com.br' && (
                <MenuItem onClick={() => { handleGoToAdmin(); handleMenuClose(); }}>
                  <AdminPanelSettings fontSize="small" sx={{ mr: 1, color: 'secondary.main' }} />
                  <Typography sx={{ color: 'secondary.main', fontWeight: 'bold' }}>
                    Painel Admin
                  </Typography>
                </MenuItem>
              )}
              {user?.email === 'willian@lexxusadm.com.br' && <Divider />}
              <MenuItem onClick={() => { setShowProfile(true); handleMenuClose(); }}>
                <AccountCircle fontSize="small" sx={{ mr: 1 }} />
                Perfil
              </MenuItem>
              <MenuItem onClick={handleLogout}>
                <Logout fontSize="small" sx={{ mr: 1 }} />
                Sair
              </MenuItem>
            </Menu>
          </Toolbar>
        </AppBar>

        {/* Cards de estatísticas fixos */}
        <Box sx={{
          backgroundColor: 'background.default',
          borderBottom: '1px solid',
          borderColor: 'divider',
          py: 2
        }}>
          <Container maxWidth="xl">
            {error && (
              <Alert severity="error" sx={{ mb: 3 }}>
                {error}
              </Alert>
            )}

            <StatsCards stats={dashboardData.stats} loading={refreshing} hideValues={hideValues} />
          </Container>
        </Box>
      </Box>

      {/* Conteúdo rolável */}
      <Container maxWidth="xl" sx={{ pt: 3, pb: 3 }}>
        <Grid container spacing={3}>
          {/* Saldo da conta */}
          <Grid item xs={12} md={4}>
            <AccountBalance balance={dashboardData.balance} loading={refreshing} hideValues={hideValues} />
          </Grid>

          {/* Card de P&L */}
          <Grid item xs={12} md={8}>
            <PNLCard 
              data={dashboardData.profitData} 
              stats={dashboardData.stats} 
              loading={refreshing} 
              hideValues={hideValues} 
            />
          </Grid>

          {/* Posições Abertas da API Bitget */}
          <Grid item xs={12}>
            <OpenPositions user={user} hideValues={hideValues} />
          </Grid>

          {/* Trades abertos (dados locais) - Temporariamente oculto */}
          {/* <Grid item xs={12}>
            <Paper sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <ShowChart color="primary" />
                  Trades Locais Abertos
                </Typography>
                <Chip
                  label={`${dashboardData.openTrades.length} trades`}
                  color="primary"
                  size="small"
                />
              </Box>
              <TradesTable trades={dashboardData.openTrades} type="open" loading={refreshing} />
            </Paper>
          </Grid> */}

          {/* Filtro de Data */}
          <Grid item xs={12}>
            <DateFilter 
              onFilterChange={handleDateFilterChange}
              currentFilters={dateFilters}
            />
          </Grid>

          {/* Histórico de trades */}
          <Grid item xs={12}>
            <Paper sx={{ p: 3 }}>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <History color="primary" />
                  Histórico de Trades
                </Typography>
                <Chip
                  label={`${dashboardData.closedTrades.length} trades`}
                  color="secondary"
                  size="small"
                />
              </Box>
              <TradesTable trades={dashboardData.closedTrades} type="closed" loading={refreshing} hideValues={hideValues} />
            </Paper>
          </Grid>
        </Grid>
      </Container>

      {/* Modal de Perfil */}
      <Profile 
        open={showProfile} 
        onClose={() => setShowProfile(false)}
        onProfileUpdate={() => {
          // Recarregar dados do usuário após atualização
          loadDashboardData();
        }}
      />
    </Box>
  );
};

export default Dashboard;
